ken parameter variable&#34;&gt;--user&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt; com.xiaomi.macro &lt;span class=&#34;token comment&#34;&gt;#自动连招&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;39&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;cmd /c adb shell pm uninstall &lt;span class=&#34;token parameter variable&#34;&gt;--user&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt; com.miui.freeform &lt;span class=&#34;token comment&#34;&gt;# 自由窗口&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;40&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;cmd /c adb shell pm uninstall &lt;span class=&#34;token parameter variable&#34;&gt;--user&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt; com.miui.carlink &lt;span class=&#34;token comment&#34;&gt;#CarWith&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;41&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;cmd /c adb shell pm uninstall &lt;span class=&#34;token parameter variable&#34;&gt;--user&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt; com.xiaomi.vipaccount &lt;span class=&#34;token comment&#34;&gt;#小米社区&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;42&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;cmd /c adb shell pm uninstall &lt;span class=&#34;token parameter variable&#34;&gt;--user&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt; com.duokan.reader &lt;span class=&#34;token comment&#34;&gt;#阅读&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;43&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;cmd /c adb shell pm uninstall &lt;span class=&#34;token parameter variable&#34;&gt;--user&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt; com.xiaomi.gamecenter &lt;span class=&#34;token comment&#34;&gt;#游戏中心&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;44&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# adb shell pm uninstall --user 0 com.miui.cit # CIT 手机测试&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;45&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;#adb shell pm uninstall --user 0 com.miui.contentcatcher # 应用程序扩展服务&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;46&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;#adb shell pm uninstall --user 0 com.miui.maintenancemode # 维修模式&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;47&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;cmd /c adb shell pm uninstall &lt;span class=&#34;token parameter variable&#34;&gt;--user&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt; com.miui.securityadd &lt;span class=&#34;token comment&#34;&gt;# 游戏加速&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;48&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;#adb shell pm uninstall --user 0 com.miui.touchassistant # 悬浮球&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;49&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;#adb shell pm uninstall --user 0 com.miui.tsmclient # 小米智能卡&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;50&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;#adb shell pm uninstall --user 0 com.miui.phrase # 常用语&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;51&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;#adb shell pm uninstall --user 0 com.mipay.wallet # 小米钱包&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;52&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;#adb shell pm uninstall