&lt;td&gt;15000000&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;2 阶段&lt;/td&gt;
&lt;td&gt;4&lt;/td&gt;
&lt;td&gt;6000000&lt;/td&gt;
